mapper.select:
SELECT DISTINCT s.id, s.school_name_cn, s.school_name_en, s.country_code, s.country_name,
  s.city_name, s.qs_rank, s.ranking_year, s.usnews_rank, s.usnews_ranking_year, s.school_summary, s.tuition_min, s.tuition_max,
  s.tuition_currency, s.duration_min_month, s.duration_max_month, s.language_requirement_range, s.advantage_subjects
FROM school s


    AND s.country_code = 'US'


    AND s.country_code = #{countryCode}


    AND EXISTS (
      SELECT 1 FROM school_subject_rel ssr
      WHERE ssr.school_id = s.id AND ssr.subject_category_code = #{subjectCategoryCode}
    )


    AND EXISTS (
      SELECT 1 FROM program p
      WHERE p.school_id = s.id AND p.direction_code = #{directionCode}
    )




        AND s.usnews_rank >= #{rankMin}


        AND s.qs_rank >= #{rankMin}






        AND s.usnews_rank <= #{rankMax}


        AND s.qs_rank <= #{rankMax}




    AND (
      s.school_name_cn LIKE CONCAT('%', #{keyword}, '%')
      OR s.school_name_en LIKE CONCAT('%', #{keyword}, '%')
      OR s.country_name LIKE CONCAT('%', #{keyword}, '%')
      OR s.country_code LIKE CONCAT('%', #{keyword}, '%')
      OR s.city_name LIKE CONCAT('%', #{keyword}, '%')
      OR s.advantage_subjects LIKE CONCAT('%', #{keyword}, '%')
      OR s.school_summary LIKE CONCAT('%', #{keyword}, '%')
    )




    ORDER BY CASE WHEN s.usnews_rank IS NULL THEN 1 ELSE 0 END ASC, s.usnews_rank ASC, s.qs_rank ASC, s.id ASC


    ORDER BY s.qs_rank ASC, s.id ASC
